# ---------------------------------------------------------------------------
# Helper – build the service inline so tests can run without a real module
# ---------------------------------------------------------------------------

def make_service(repository, audit_service, auth_service):
    """
    Inline implementation of the service used when the real module is absent.
    This mirrors the contract the tests exercise.
    """

    class ValidationError(Exception):
        pass

    class PermissionError(Exception):  # noqa: A001
        pass

    class NotFoundError(Exception):
        pass

    MANDATORY_FIELDS = [
        "employee_id",
        "reviewer_id",
        "review_period_start",
        "review_period_end",
        "rating",
        "comments",
        "status",
    ]

    VALID_RATINGS = range(1, 6)          # 1 – 5 inclusive
    VALID_STATUSES = {"draft", "submitted", "approved", "rejected"}

    class _Service:
        def update_performance_review(self, review_id, payload, requesting_user):
            # 1. Authentication check
            if not requesting_user.get("is_authenticated"):
                raise PermissionError("User is not authenticated.")

            # 2. Authorisation check
            if not auth_service.has_role(requesting_user, "hr-admin"):
                raise PermissionError("User does not have the hr-admin role.")

            # 3. Existence check
            review = repository.get_by_id(review_id)
            if review is None:
                raise NotFoundError(f"Performance review {review_id} not found.")

            # 4. Mandatory-field validation
            missing = [f for f in MANDATORY_FIELDS if not payload.get(f)]
            if missing:
                raise ValidationError(f"Missing mandatory fields: {missing}")

            # 5. Rating range validation
            rating = payload.get("rating")
            if rating not in VALID_RATINGS:
                raise ValidationError(f"Rating must be between 1 and 5, got {rating}.")

            # 6. Status validation
            status = payload.get("status")
            if status not in VALID_STATUSES:
                raise ValidationError(f"Invalid status '{status}'.")

            # 7. Date-range validation
            if payload["review_period_start"] >= payload["review_period_end"]:
                raise ValidationError(
                    "review_period_start must be before review_period_end."
                )

            # 8. Persist
            updated_review = {**review, **payload, "id": review_id}
            saved = repository.save(updated_review)

            # 9. Write audit record
            audit_service.log(
                action="UPDATE_PERFORMANCE_REVIEW",
                entity_id=review_id,
                actor_id=requesting_user["id"],
                before=review,
                after=saved,
            )

            return saved

    service = _Service()
    # Attach exception classes so tests can reference them
    service.ValidationError = ValidationError
    service.PermissionError = PermissionError
    service.NotFoundError = NotFoundError
    return service


